// NODO: UI_Adapter_Ban
// VERSIONE: 1.1 - Protocollo Sicurezza Formale

const item = $input.first().json;

if (item.routingDecision === 'BAN_HANDLER') {

    const owner = item.owner_data || {};
    const session = item.active_session || {};
    const chatId = item.user_request.chat_id.toString();
    const oldBotMsgId = session.telegram?.last_bot_message_id;

    const companyName = owner.ragione_sociale ? owner.ragione_sociale.toUpperCase() : "SISTEMA";

    // 1. MESSAGGIO DI BAN (Formale, Legale, Diretto)
    let messageText = `🚫 <b>RESTRIZIONE DI ACCESSO APPLICATA</b>\n`;
    messageText += `━━━━━━━━━━━━━━━━━━━━\n\n`;
    messageText += `Gentile utente, la informiamo che i sistemi di sicurezza di <b>${companyName}</b> hanno rilevato violazioni reiterate dei Termini di Servizio da parte di questo account.\n\n`;
    messageText += `Ai sensi delle nostre policy di sicurezza informatica, il Suo identificativo Telegram (ID: <code>${chatId}</code>) è stato <b>permanentemente sospeso</b> dall'utilizzo di questa piattaforma.\n\n`;
    messageText += `Ogni ulteriore input non verrà elaborato dai nostri server.\n\n`;
    messageText += `<i>Per contestare questo provvedimento, può inviare una comunicazione formale all'indirizzo email: assistenza@trinai.it indicando il Suo ID Telegram.</i>`;

    // 2. PREPARAZIONE PAYLOAD REFRESH (Rimozione UI)
    item.telegramDeletePayload = oldBotMsgId ? {
        method: "deleteMessage",
        chat_id: chatId,
        message_id: oldBotMsgId
    } : null;

    item.telegramApiPayload = {
        method: "sendMessage",
        chat_id: chatId,
        text: messageText,
        parse_mode: "HTML",
        disable_web_page_preview: true,
        // Eliminazione totale della UI
        reply_markup: { remove_keyboard: true }
    };
}

return [item];

