// NODO: Session_Initializer
// VERSIONE: 8.0 - MIME Aware for Gemini

const item = $input.first().json;
const msg = item.body?.message || {};
const owner = item.owner_data || {};
const config = owner.customer_bot_config || {};
const perms = config.permissions || { allow_images: false, allow_files: false };

const MAX_FILE_SIZE_BYTES = 5 * 1024 * 1024;

let type = "text";
let mediaData = null;
let fileSize = 0;

const extractedText = msg.text || msg.caption || "";

// Media detection + MIME capture
if (msg.photo) {
  type = "photo";
  const lastPhoto = msg.photo[msg.photo.length - 1];
  fileSize = lastPhoto.file_size || 0;

  mediaData = {
    file_id: lastPhoto.file_id,
    file_unique_id: lastPhoto.file_unique_id || null,
    size: fileSize,
    mime_type: "image/jpeg"
  };

} else if (msg.document) {
  type = "document";
  fileSize = msg.document.file_size || 0;

  mediaData = {
    file_id: msg.document.file_id,
    file_unique_id: msg.document.file_unique_id || null,
    name: msg.document.file_name || null,
    size: fileSize,
    mime_type: msg.document.mime_type || "application/octet-stream"
  };

} else if (msg.video) {
  type = "video";
  fileSize = msg.video.file_size || 0;

  mediaData = {
    file_id: msg.video.file_id,
    file_unique_id: msg.video.file_unique_id || null,
    size: fileSize,
    mime_type: msg.video.mime_type || "video/mp4"
  };

} else if (msg.voice) {
  type = "voice";
  fileSize = msg.voice.file_size || 0;

  mediaData = {
    file_id: msg.voice.file_id,
    file_unique_id: msg.voice.file_unique_id || null,
    duration: msg.voice.duration || null,
    size: fileSize,
    mime_type: msg.voice.mime_type || "audio/ogg"
  };

} else if (msg.audio) {
  type = "audio";
  fileSize = msg.audio.file_size || 0;

  mediaData = {
    file_id: msg.audio.file_id,
    file_unique_id: msg.audio.file_unique_id || null,
    name: msg.audio.file_name || null,
    duration: msg.audio.duration || null,
    performer: msg.audio.performer || null,
    title: msg.audio.title || null,
    size: fileSize,
    mime_type: msg.audio.mime_type || "audio/mpeg"
  };

} else if (msg.video_note) {
  type = "video_note";
  fileSize = msg.video_note.file_size || 0;

  mediaData = {
    file_id: msg.video_note.file_id,
    file_unique_id: msg.video_note.file_unique_id || null,
    duration: msg.video_note.duration || null,
    length: msg.video_note.length || null,
    size: fileSize,
    mime_type: "video/mp4"
  };
}

// Policy validation
let isAllowed = true;

if ((type === "photo" || type === "video" || type === "video_note") && !perms.allow_images) {
  isAllowed = false;
} else if ((type === "document" || type === "voice" || type === "audio") && !perms.allow_files) {
  isAllowed = false;
}

if (isAllowed && type !== "text" && fileSize > MAX_FILE_SIZE_BYTES) {
  isAllowed = false;
}

// User request
const user_request = {
  text: extractedText,
  chat_id: msg.chat?.id || null,
  message_id: msg.message_id || null,
  language: msg.from?.language_code || "it",
  type,
  media_info: mediaData,
  has_media: !!mediaData,
  timestamp: new Date().toISOString()
};

// Active session
let active_session = item.active_session;
const ownerChatId = item.query?.user_id || null;
const compositeSessionId = `${user_request.chat_id}-${ownerChatId}`;

if (!active_session) {
  active_session = {
    _id: compositeSessionId,
    session_id: compositeSessionId,
    owner_chatid: ownerChatId,
    customer_chatid: user_request.chat_id,
    session_status: "ACTIVE",
    lead_profile: {
      first_name: msg.from?.first_name || "",
      last_name: msg.from?.last_name || "",
      username: msg.from?.username || "",
      language: user_request.language
    },
    preferences: {
      broadcast_subscribed: false,
      last_preference_update: user_request.timestamp
    },
    prediction_keywords: "accoglienza, chi siamo, dove siete, cosa fate",
    working_memory: {
      behavioral_log: "",
      funnel_step: "start"
    },
    telegram: {
      last_bot_message_id: null,
      last_interaction: user_request.timestamp
    }
  };
} else {
  if (!active_session.telegram) active_session.telegram = {};
  active_session.telegram.last_interaction = user_request.timestamp;
}

// Delete payload if blocked
let deletePayload = null;

if (!isAllowed) {
  deletePayload = {
    method: "deleteMessage",
    chat_id: user_request.chat_id,
    message_id: user_request.message_id
  };
}

return [{
  json: {
    owner_data: owner,
    stakeholder: item.stakeholder,
    user_request,
    active_session,
    routing_decision: isAllowed ? "ALLOWED" : "BLOCKED",
    telegramDeletePayload: deletePayload
  }
}];

/**
 * NODO: SAM'S - VENOMHEARTH (Italian Ultra-Core Edition)
 * ADATTAMENTO: Architettura Ottimizzata TrinAI
 * OBIETTIVO: Ricerca semantica ad altissima precisione esclusiva per la lingua italiana.
 */

// =============================================================================
// --- IMPOSTAZIONE DEL FILTRO (UNICO PARAMETRO DI CONTROLLO) ---
// Range: da 1 a 10
// - 1  = Filtro STRETTISSIMO (richiede corrispondenze esatte e alta densità)
// - 5  = Filtro BILANCIATO (impostazione standard consigliata)
// - 10 = Filtro APERTISSIMO (mostra risultati anche con minime parole in comune)
// =============================================================================
const SENSITIVITY = 5; 

// =============================================================================
// --- CONFIGURAZIONE INTERNA ---
// =============================================================================
const minTokenLength = 2;
const useNgrams = true;
const coreIdentityFragmentId = 'CORE_IDENTITY_001';

const scoringWeights = {
  utterance_ngram: 12,
  utterance_exact: 8,
  question_ngram: 10,
  question_exact: 5,
  title_exact: 4,
  answer_fragment_exact: 2,
  summary_exact: 2,
  answer_exact: 1,
  analogy_exact: 0.5
};

// Dizionario espanso di stopwords e rumore conversazionale in italiano
const italianStopwords = new Set([
  'il', 'la', 'lo', 'i', 'gli', 'le', 'un', 'una', 'uno', 'dei', 'degli', 'delle', 'del', 'dello', 'della', 'al', 'allo', 'alla', 'ai', 'agli', 'alle',
  'di', 'a', 'da', 'in', 'con', 'su', 'per', 'tra', 'fra', 'ed', 'ad', 'od',
  'che', 'chi', 'cui', 'quale', 'quali', 'questo', 'questa', 'questi', 'queste', 'quello', 'quella', 'quelli', 'quelle',
  'mio', 'mia', 'miei', 'mie', 'tuo', 'tua', 'tuoi', 'tue', 'suo', 'sua', 'suoi', 'sue', 'nostro', 'nostra', 'nostri', 'nostre', 'vostro', 'vostra', 'vostri', 'vostre', 'loro',
  'io', 'tu', 'lui', 'lei', 'noi', 'voi', 'loro', 'mi', 'ti', 'ci', 'vi', 'si', 'me', 'te', 'se', 'lo', 'la', 'li', 'le', 'ne',
  'ho', 'hai', 'ha', 'abbiamo', 'avete', 'hanno', 'avevo', 'avevi', 'aveva', 'avevamo', 'avevate', 'avevano', 'ebbi', 'avesti', 'ebbe', 'avemmo', 'aveste', 'ebbero', 'avrò', 'avrai', 'avrà', 'avremo', 'avrete', 'avranno', 'avrei', 'avresti', 'avrebbe', 'avremmo', 'avreste', 'avrebbero', 'avendo', 'avuto', 'avuta', 'avuti', 'avute',
  'sono', 'sei', 'è', 'siamo', 'siete', 'era', 'eravamo', 'eravate', 'erano', 'fui', 'fosti', 'fu', 'fummo', 'foste', 'furono', 'sarò', 'sarai', 'sarà', 'saremo', 'sarete', 'saranno', 'sarei', 'saresti', 'sarebbe', 'saremmo', 'sareste', 'sarebbero', 'essendo', 'stato', 'stata', 'stati', 'state',
  'ma', 'o', 'oppure', 'ovvero', 'anche', 'ancora', 'invece', 'bensì', 'inoltre', 'tuttavia', 'però', 'ossia', 'cioè',
  'vorrei', 'voglio', 'vorremmo', 'vogliamo', 'posso', 'possono', 'potrei', 'potrebbe', 'potremmo', 'potrebbero', 'devo', 'deve', 'dovrei', 'dovrebbe', 'dovremmo', 'dovrebbero', 'sapere', 'conoscere', 'capire', 'chiedere', 'domandare', 'informazioni', 'info',
  'ciao', 'salve', 'buongiorno', 'buonasera', 'grazie', 'prego', 'per favore', 'gentilmente', 'scusa', 'scusi', 'cortesemente', 'saluti', 'saluto',
  'più', 'meno', 'molto', 'poco', 'troppo', 'tanto', 'tanti', 'tante', 'tutto', 'tutta', 'tutti', 'tutte', 'nulla', 'niente', 'qualcosa',
  'si', 'no', 'non', 'forse', 'magari', 'circa', 'sopra', 'sotto', 'dentro', 'fuori', 'prima', 'dopo', 'ora', 'adesso', 'poi', 'allora'
]);

// =============================================================================
// --- FUNZIONI DI ELABORAZIONE LINGUISTICA (ITALIAN ONLY) ---
// =============================================================================

// Normalizza i caratteri accentati (es: perché -> perche)
function stripAccents(text) {
  return text.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
}

// Generatore di N-Grams per l'analisi sequenziale
function generateNgrams(tokens, n) {
  const ngrams = [];
  for (let i = 0; i <= tokens.length - n; i++) {
    ngrams.push(tokens.slice(i, i + n).join(' '));
  }
  return ngrams;
}

// Stemmer avanzato per unificare i suffissi, i plurali e le coniugazioni italiane
function stemItalian(word) {
  word = stripAccents(word.toLowerCase().trim());
  if (word.length <= 3) return word;

  const suffixes = [
    // Coniugazioni verbali e tempi complessi
    'asseremmo', 'assereste', 'asseresti', 'assero', 'assimo', 'eremmo', 'ereste', 'eresti', 'essero', 'essimo', 'iremo', 'irete', 'irono', 'ireste', 'iresti', 'issero', 'issimo', 'eranno', 'erebbero',
    // Suffissi derivativi complessi
    'izzazione', 'izzazioni', 'icamente', 'amento', 'amenti', 'azione', 'azioni', 'atore', 'atori', 'atrice', 'atrici', 'abile', 'abili', 'ibile', 'ibili', 'mente', 'ezza', 'ezze',
    // Gradi degli aggettivi
    'issimo', 'issima', 'issimi', 'issime', 'icissimo', 'icissima', 'icissimi', 'icissime',
    // Terminologie mediche/scientifiche ricorrenti
    'ologia', 'ologie', 'ogico', 'ogica', 'ogici', 'ogiche',
    'odontico', 'odontica', 'odontici', 'odontiche',
    'chirurgico', 'chirurgica', 'chirurgici', 'chirurgiche',
    'estetico', 'estetica', 'estetici', 'estetiche',
    // Coniugazioni standard, gerundi e participi
    'assero', 'assimo', 'eranno', 'eremo', 'erete', 'erono', 'iranno', 'iremo', 'irete', 'irono', 'iscano', 'iscono', 'iscite', 'isciti', 'iscito',
    'ando', 'endo', 'ante', 'anti', 'ente', 'enti',
    'ato', 'ata', 'ati', 'ate', 'uto', 'uta', 'uti', 'ute', 'ito', 'ita', 'iti', 'ite',
    'ico', 'ica', 'ici', 'iche', 'oso', 'osa', 'osi', 'ose', 'ivo', 'iva', 'ivi', 'ive', 'are', 'ere', 'ire', 'ale', 'ali',
    // Diminutivi e accrescitivi comuni
    'ino', 'ina', 'ini', 'ine', 'one', 'ona', 'oni', 'one', 'etto', 'etta', 'etti', 'ette'
  ];

  for (const suffix of suffixes) {
    if (word.endsWith(suffix) && word.length - suffix.length >= 3) {
      return word.slice(0, -suffix.length);
    }
  }

  // Semplificazione desinenze finali per ricondurre al tema principale
  if (word.endsWith('e') || word.endsWith('i') || word.endsWith('o') || word.endsWith('a')) {
    return word.slice(0, -1);
  }

  return word;
}

function cleanText(text) {
  if (!text) return "";
  return text.toLowerCase()
             .replace(/['’]/g, " ") // Sostituisce gli apostrofi con uno spazio
             .replace(/[.,\/#!$%\^&\*;:{}=\-_`~()?\¿\¡"']/g, " ") // Rimuove la punteggiatura
             .replace(/\s+/g, ' ') // Normalizza gli spazi multipli
             .trim();
}

function preprocessQuery(text) {
  const cleanedText = cleanText(text);
  const rawTokens = cleanedText.split(/\s+/).filter(word => word.length >= minTokenLength && !italianStopwords.has(word));
  const stemmedTokens = rawTokens.map(word => stemItalian(word));
  return { rawTokens, stemmedTokens, uniqueTokens: [...new Set(stemmedTokens)] };
}

// =============================================================================
// --- LOGICA DI INSTRADAMENTO E FILTRAGGIO ---
// =============================================================================
const inputData = $input.first().json;

const userMessage = inputData.user_request?.text || "";
const conversationHistory = inputData.conversation_history || [];

// Modificato qui: ora legge dal nuovo oggetto pulito "Knowledge"
const fragments = inputData.Knowledge?.knowledge_fragments || [];

// Lettura flessibile della chiave di routing
const routingDecision = inputData.routingDecision || inputData.routing_decision;

// Bypass per i rami di sicurezza e risposte dirette pre-confezionate
const bypassRoutes = ['oHODOR', 'BAN_HANDLER', 'Direct_Response'];
if (bypassRoutes.includes(routingDecision) || fragments.length === 0) {
  return [{ json: {
    ...inputData, 
    selected_fragments: [],
    librarian_meta: {
      routing_decision_handled: routingDecision,
      mission_status: fragments.length === 0 ? 'NO_DATA' : 'BYPASS_ACTIVE',
      timestamp: new Date().toISOString()
    }
  }}];
}

// Traduzione matematica del valore SENSITIVITY (1-10) nelle soglie di punteggio e densità
const absoluteThreshold = Math.max(0.1, 13 - SENSITIVITY * 1.3);
const densityMinPercent = Math.max(0, (10 - SENSITIVITY) * 0.04);

// Elaborazione linguistica della query utente corrente
const currentQuery = preprocessQuery(userMessage);

// Elaborazione linguistica dello storico della conversazione
let conversationTokens = [];
const userTurns = conversationHistory.filter(turn => turn.role === 'user');
if (userTurns.length > 0) {
  const lastTurnText = userTurns[userTurns.length - 1].content || "";
  const historyQuery = preprocessQuery(lastTurnText);
  conversationTokens = historyQuery.uniqueTokens;
}

// Integrazione delle parole chiave predittive
let enrichmentTokens = [];
const predictionKeywords = inputData.active_session?.prediction_keywords;
if (predictionKeywords && predictionKeywords.trim().length > 0) {
  predictionKeywords.split(',').forEach(kw => {
    const processed = preprocessQuery(kw.trim());
    enrichmentTokens.push(...processed.uniqueTokens);
  });
}
enrichmentTokens = [...new Set(enrichmentTokens)];

const finalQueryTokens = [...new Set([...conversationTokens, ...currentQuery.uniqueTokens, ...enrichmentTokens])];
const finalRawTokens = [...conversationTokens, ...currentQuery.rawTokens, ...enrichmentTokens];

// Indicizzazione e pulizia preventiva dei frammenti di conoscenza
const fragsWithTokens = fragments.map(fragment => {
  const pre = { tokenSets: {} };

  if (fragment.user_utterances) {
    pre.utterances_text = cleanText(fragment.user_utterances.join(' '));
    pre.tokenSets.utterances = pre.utterances_text.split(/\s+/).map(w => stemItalian(w));
  }
  if (fragment.title) {
    pre.title_text = cleanText(fragment.title);
    pre.tokenSets.title = pre.title_text.split(/\s+/).map(w => stemItalian(w));
  }
  if (fragment.answer_fragment) {
    pre.answer_text = cleanText(fragment.answer_fragment);
    pre.tokenSets.answer = pre.answer_text.split(/\s+/).map(w => stemItalian(w));
  }
  if (fragment.sections) {
    // Indicizzazione domande delle sezioni
    pre.questions_text = cleanText(fragment.sections.map(s => s.question).join(' '));
    pre.tokenSets.questions = pre.questions_text.split(/\s+/).map(w => stemItalian(w));

    // NUOVO: Indicizzazione risposte delle sezioni
    pre.answers_text = cleanText(fragment.sections.map(s => s.answer).join(' '));
    pre.tokenSets.answers = pre.answers_text.split(/\s+/).map(w => stemItalian(w));
  }

  return { ...fragment, _precomputed: pre };
});

// Calcolo della prossimità semantica tramite N-Grams e token esatti
const queryNgrams = [...generateNgrams(finalRawTokens, 2), ...generateNgrams(finalRawTokens, 3)];

const scoredFragments = fragsWithTokens.map(f => {
  let score = 0;
  const matchedUniqueTokens = new Set();
  const pre = f._precomputed;

  if (useNgrams) {
    queryNgrams.forEach(ngram => {
      const normalizedNgram = stripAccents(ngram);
      if (pre.utterances_text?.includes(normalizedNgram)) score += scoringWeights.utterance_ngram;
      if (pre.questions_text?.includes(normalizedNgram)) score += scoringWeights.question_ngram;
    });
  }

  finalQueryTokens.forEach(token => {
    let matched = false;
    if (pre.tokenSets.utterances?.includes(token)) { score += scoringWeights.utterance_exact; matched = true; }
    if (pre.tokenSets.questions?.includes(token)) { score += scoringWeights.question_exact; matched = true; }
    if (pre.tokenSets.title?.includes(token)) { score += scoringWeights.title_exact; matched = true; }
    if (pre.tokenSets.answer?.includes(token)) { score += scoringWeights.answer_fragment_exact; matched = true; }
    if (pre.tokenSets.answers?.includes(token)) { score += scoringWeights.answer_fragment_exact; matched = true; } // Scoring risposte sezioni

    if (matched) matchedUniqueTokens.add(token);
  });

  // Divisore impostato sulla lunghezza della query corrente per non penalizzare i match precisi in caso di storico lungo
  const divisor = currentQuery.uniqueTokens.length || 1;
  return { ...f, _score: score, _density: matchedUniqueTokens.size / divisor };
});

// Filtraggio definitivo in base ai parametri di sensibilità attivi
let finalSelection = scoredFragments.filter(f => f._score >= absoluteThreshold)
                                    .filter(f => f._density >= densityMinPercent)
                                    .sort((a, b) => b._score - a._score);

// NUOVO: Consente di campionare fino a un massimo di 3 elementi pertinenti simultaneamente
const maxTargetCount = Math.min(3, fragments.length);
finalSelection = finalSelection.slice(0, maxTargetCount);

// Fallback di stabilità: se nessun frammento passa le soglie, restituisce il record di identità core
if (finalSelection.length === 0) {
  const coreFragment = fragsWithTokens.find(f => f.fragment_id === coreIdentityFragmentId);
  if (coreFragment) finalSelection = [coreFragment];
}

return [{ json: {
  ...inputData,
  selected_fragments: finalSelection.map(({_score, _density, _precomputed, ...clean}) => clean),
  librarian_meta: {
    calculated_threshold: absoluteThreshold,
    calculated_density: densityMinPercent,
    sensitivity_set: SENSITIVITY,
    routing_decision_handled: routingDecision,
    selection_count: finalSelection.length,
    mission_status: finalSelection.length > 0 ? 'SUCCESS' : 'NO_TARGETS',
    timestamp: new Date().toISOString()
  }
}}];

// NODO: Burst_Cleaner
// OBIETTIVO: Eliminare il messaggio corrente e terminare l'esecuzione

