function isPureGreeting(text) {
    const normalized = text.trim().toLowerCase().replace(/[.,!?;:()\[\]{}]/g, '');
    const words = normalized.split(/\s+/).filter(w => w.length > 0);
    if (words.length > 3) return false;
    return PURE_GREETING_PATTERNS_COMPILED.some(pattern => pattern.test(normalized));
}

function isSchedulingIntent(text) { return SCHEDULING_PATTERNS_COMPILED.some(p => p.test(text.toLowerCase())); }
function isBusinessIntent(text) { return BUSINESS_PATTERNS_COMPILED.some(p => p.test(text.toLowerCase())); }
function isKnowledgeQuestion(text) { return KNOWLEDGE_PATTERNS_COMPILED.some(pattern => pattern.test(text.toLowerCase())); }

const KEYWORD_MAP = new Map();
function initKeywords() {
    const keywords = {
        negation: [['no', 1.2], ['non', 1.2], ['niente', 1.0], ['non voglio', 1.5], ['annulla', 1.2], ['stop', 1.3]],
        greeting: [['ciao', 1.0], ['salve', 1.0], ['buongiorno', 1.0]],
        identity: [['chi sei', 1.0], ['come ti chiami', 1.0]],
        scheduling: [['appuntamento', 1.0], ['fissare', 1.0], ['meeting', 1.0]],
        business: [['comprare', 1.0], ['acquistare', 1.0], ['offerta', 1.0], ['prezzi', 0.9]],
        knowledge: [['cos\'è', -0.5], ['come funziona', -0.5]]
    };
    for (const [cat, ent] of Object.entries(keywords)) {
        for (const [kw, w] of ent) KEYWORD_MAP.set(`${cat}_${kw.toLowerCase()}`, { category: cat, weight: w });
    }
}
initKeywords();

function analyzeIntent(text) {
    const scores = { negation: 0, greeting: 0, identity: 0, scheduling: 0, business: 0, knowledge: 0, security_threats: 0 };
    const normalized = text.trim().toLowerCase();
    for (const p of THREAT_PATTERNS_COMPILED) { if (p.test(normalized)) scores.security_threats += 2.0; }
    const words = normalized.replace(/[.,!?;:()\[\]{}]/g, ' ').split(/\s+/).filter(w => w.length > 0);
    const intentCategories = ['negation', 'greeting', 'identity', 'scheduling', 'business', 'knowledge'];
    for (let windowSize = 3; windowSize >= 1; windowSize--) {
        for (let i = 0; i <= words.length - windowSize; i++) {
            const phrase = words.slice(i, i + windowSize).join(' ');
            for (const cat of intentCategories) {
                if (KEYWORD_MAP.has(`${cat}_${phrase}`)) scores[cat] += KEYWORD_MAP.get(`${cat}_${phrase}`).weight;
            }
        }
    }
    return scores;
}

function resolvePrimaryIntent(scores) {
    const detected = [];
    for (const [intent, score] of Object.entries(scores)) {
        if (score >= THRESHOLDS.lowConfidence) detected.push({ intent, score, priority: INTENT_PRIORITIES[intent] });
    }
    if (detected.length === 0) return { primaryIntent: null };
    detected.sort((a, b) => a.priority - b.priority || b.score - a.score);
    return { primaryIntent: detected[0].intent };
}

